class MyCircularQueue:
    def __init__(self, k):
        self.q = [0]*k
        self.head = 0
        self.count = 0
        self.k = k
    def enQueue(self, value):
        if self.isFull(): return False
        self.q[(self.head + self.count) % self.k] = value
        self.count += 1
        return True
    def deQueue(self):
        if self.isEmpty(): return False
        self.head = (self.head + 1) % self.k
        self.count -= 1
        return True
    def Front(self):
        return -1 if self.isEmpty() else self.q[self.head]
    def Rear(self):
        return -1 if self.isEmpty() else self.q[(self.head + self.count - 1) % self.k]
    def isEmpty(self):
        return self.count == 0
    def isFull(self):
        return self.count == self.k

def solveCircularQueue(commands, args):
    q = None
    res = []
    for cmd, arg in zip(commands, args):
        if cmd == "MyCircularQueue": q = MyCircularQueue(arg[0]); res.append(None)
        elif cmd == "enQueue": res.append(q.enQueue(arg[0]))
        elif cmd == "deQueue": res.append(q.deQueue())
        elif cmd == "Front": res.append(q.Front())
        elif cmd == "Rear": res.append(q.Rear())
        elif cmd == "isEmpty": res.append(q.isEmpty())
        elif cmd == "isFull": res.append(q.isFull())
    return res

